import React from 'react';

export interface TooltipInfo {
  title: string;
  shortText: string;
  details: React.ReactNode;
}

export interface InputParams {
  businessModel: 'Direct Sales' | 'Leasing';
  unitSystem: 'gallons' | 'liters';
  unitsPerClient: number;
  numberOfClients: number;
  companyHandlesInstallation: boolean;
  enableCashFlowDiscounting: boolean;
  discountRate: number;
  enableCarbonCredits: boolean;
  pricePerCredit: number;
  avgGasolineSold: number;
  recoveryRate: number;
  gasolinePrice: number;
  companyRevenueShare: number;
  leaseTerm: number;
  machineUptime: number;
  electricityPrice: number;
  annualMaintenanceCost: number;
  unitSalePrice: number;
  volumeGrowthRate: number;
  annualConsumablesCost: number;
  annualWarrantyCost: number;
  dailyOperationalCost: number;

  // Constants
  installationCostPerUnit: number;
  customerAcquisitionCost: number;
  unitCost: number;
  unitElectricityConsumptionKwhDay: number;
  co2TonnesPerGallon: number;

  // SaaS / Monthly Fees
  enableMonthlyFees: boolean;
  monthlyFeePerUnit: number;

  // Advanced Project Finance
  enableFinancing: boolean;
  loanDownPaymentPercent: number; // 0-100
  loanInterestRate: number; // %
  loanTermYears: number;
  corporateTaxRate: number; // %
  depreciationPeriod: number; // years
}

export interface CalculatedResults {
  totalUnitsSold: number;
  revenue: {
    salesRevenue: number;
    leasingRevenue: number;
    installationRevenue: number;
    carbonCreditRevenue: number;
    monthlyFeeRevenue: number;
    totalRevenue: number;
  };
  costs: {
    cogs: number;
    installationCost: number;
    maintenanceCost: number;
    electricityCost: number;
    consumablesCost: number;
    warrantyCost: number;
    operationalCost: number;
    customerAcquisitionCost: number;
    loanInterestCost: number;
    totalCosts: number;
    totalTaxes: number;
  };
  profitability: {
    grossProfit: number;
    ebitda: number;
    netProfit: number; // After tax
    profitMargin: number;
    roi: number;
    npv: number;
  };
  cashFlow: number[];
}

export interface Station {
  id: string;
  name: string;
  dailyVolume: number;
  recoveryRate: number;
  uptime: number;
  installCost: number;
}

export interface Scenario {
  id: string;
  name: string;
  date: string;
  params: InputParams;
}

export type AnalyzableVariable = 
  | 'avgGasolineSold'
  | 'recoveryRate'
  | 'gasolinePrice'
  | 'companyRevenueShare'
  | 'leaseTerm'
  | 'unitsPerClient'
  | 'pricePerCredit'
  | 'unitSalePrice';

export type AnalyzableMetric = 'netProfit' | 'npv' | 'roi' | 'totalRevenue';

import { InputParams, CalculatedResults } from '../types';

export const calculateVaporRecovery = (params: InputParams): CalculatedResults => {
  const totalUnitsSold = params.unitsPerClient * params.numberOfClients;
  const LITER_PER_GALLON = 3.78541;

  // Constants & Conversions
  const co2TonnesPerVolumeUnit = params.unitSystem === 'gallons'
    ? params.co2TonnesPerGallon
    : params.co2TonnesPerGallon / LITER_PER_GALLON;

  const durationYears = params.leaseTerm;

  // --- REVENUE CALCULATIONS ---

  const installationRevenue = params.companyHandlesInstallation ? totalUnitsSold * params.installationCostPerUnit : 0;
  const salesRevenue = params.businessModel === 'Direct Sales' ? totalUnitsSold * params.unitSalePrice : 0;

  // --- LOAN SETUP ---
  const initialCapEx = (totalUnitsSold * params.unitCost) + (params.companyHandlesInstallation ? 0 : (totalUnitsSold * params.installationCostPerUnit));
  // Note: We assume "Installation Cost" is a cost to the company if companyHandlesInstallation is true.
  // If companyHandlesInstallation is false, the company doesn't pay it, so it's not in the loan principal logic for the company.
  // Actually, usually CapEx = Unit Cost + Install Cost (if company pays).

  let loanPrincipal = 0;
  let annualLoanPayment = 0;

  if (params.enableFinancing) {
      const totalInvestment = (totalUnitsSold * params.unitCost) + 
          (params.companyHandlesInstallation ? totalUnitsSold * params.installationCostPerUnit : 0);

      const downPayment = totalInvestment * (params.loanDownPaymentPercent / 100);
      loanPrincipal = totalInvestment - downPayment;

      // PMT Calculation
      if (loanPrincipal > 0 && params.loanInterestRate > 0) {
          const r = params.loanInterestRate / 100;
          const n = params.loanTermYears;
          // Annual payment formula
          annualLoanPayment = (loanPrincipal * r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1);
      } else if (loanPrincipal > 0) {
          annualLoanPayment = loanPrincipal / params.loanTermYears;
      }
  }

  // --- LOOP ---
  let totalLeasingRevenue = 0;
  let totalRecoveredVolume = 0;
  let totalMonthlyFeeRevenue = 0;
  let totalLoanInterestCost = 0;
  let totalTaxableIncome = 0;
  let totalTaxes = 0;

  // Cost Aggregators
  const cogs = totalUnitsSold * params.unitCost;
  const installationCost = params.companyHandlesInstallation ? totalUnitsSold * params.installationCostPerUnit : 0;
  const customerAcquisitionCost = params.customerAcquisitionCost;

  // OpEx per year
  const isLeasing = params.businessModel === 'Leasing';
  const annualMaintenance = totalUnitsSold * params.annualMaintenanceCost;
  const annualWarranty = totalUnitsSold * params.annualWarrantyCost;
  const annualConsumables = totalUnitsSold * params.annualConsumablesCost;
  const annualOperational = totalUnitsSold * params.dailyOperationalCost * 365;
  const annualElectricityCostPerUnit = params.unitElectricityConsumptionKwhDay * 365 * params.electricityPrice;
  const totalAnnualElectricity = totalUnitsSold * annualElectricityCostPerUnit;
  const annualFixedOpEx = annualMaintenance + annualWarranty + annualConsumables + annualOperational + (isLeasing ? totalAnnualElectricity : 0);

  // Cash Flow Setup
  // Initial Outflow: 
  // If Financing: DownPayment + CAC + (Install Cost if not in loan? Assumed in loan)
  // Let's assume CAC is NOT financed usually.

  let initialOutflow = 0;
  if (params.enableFinancing) {
      const totalInvestment = cogs + installationCost;
      const downPayment = totalInvestment * (params.loanDownPaymentPercent / 100);
      initialOutflow = downPayment + customerAcquisitionCost;
  } else {
      initialOutflow = cogs + installationCost + customerAcquisitionCost;
  }

  // Year 0 Cashflow (Investment)
  const cashFlow: number[] = [-initialOutflow];

  // Depreciation
  const annualDepreciation = (cogs + installationCost) / params.depreciationPeriod;

  // Loop years
  let currentLoanBalance = loanPrincipal;

  for (let year = 1; year <= durationYears; year++) {
    const growthFactor = Math.pow(1 + (params.volumeGrowthRate / 100), year - 1);

    // 1. REVENUE
    let yearRevenue = 0;

    // One-time Sales
    if (year === 1 && params.businessModel === 'Direct Sales') yearRevenue += salesRevenue;
    if (year === 1 && params.companyHandlesInstallation) yearRevenue += installationRevenue;

    // Recurring Leasing
    const dailyVolThisYear = params.avgGasolineSold * growthFactor;
    const recoveredThisYear = dailyVolThisYear * totalUnitsSold * (params.recoveryRate / 100) * 365 * (params.machineUptime / 100);

    if (params.businessModel === 'Leasing') {
        const leaseRev = recoveredThisYear * params.gasolinePrice * (params.companyRevenueShare / 100);
        yearRevenue += leaseRev;
        totalLeasingRevenue += leaseRev;
    }
    totalRecoveredVolume += recoveredThisYear;

    // Carbon
    if (params.enableCarbonCredits) {
        const carbonRev = (recoveredThisYear * co2TonnesPerVolumeUnit) * params.pricePerCredit;
        yearRevenue += carbonRev;
    }

    // SaaS
    if (params.enableMonthlyFees) {
        const saasRev = totalUnitsSold * params.monthlyFeePerUnit * 12;
        yearRevenue += saasRev;
        totalMonthlyFeeRevenue += saasRev;
    }

    // 2. OPEX
    const yearOpEx = annualFixedOpEx; // Simplified constant OpEx

    // 3. EBITDA
    const ebitda = yearRevenue - yearOpEx;

    // 4. FINANCING COSTS (Interest)
    let interestPayment = 0;
    let principalPayment = 0;

    if (params.enableFinancing && year <= params.loanTermYears && currentLoanBalance > 0) {
        interestPayment = currentLoanBalance * (params.loanInterestRate / 100);
        principalPayment = annualLoanPayment - interestPayment;
        if (principalPayment > currentLoanBalance) principalPayment = currentLoanBalance; // Cap last payment
        currentLoanBalance -= principalPayment;
    }
    totalLoanInterestCost += interestPayment;

    // 5. DEPRECIATION (Non-cash expense for Tax)
    const depreciation = (year <= params.depreciationPeriod) ? annualDepreciation : 0;

    // 6. TAX
    const taxableIncome = ebitda - interestPayment - depreciation;
    let tax = 0;
    if (taxableIncome > 0 && params.corporateTaxRate > 0) {
        tax = taxableIncome * (params.corporateTaxRate / 100);
    }
    totalTaxes += tax;
    totalTaxableIncome += taxableIncome;

    // 7. NET INCOME (Accounting Profit)
    const netIncome = taxableIncome - tax; // Note: this "Net Income" includes depreciation deduction

    // 8. CASH FLOW (Actual cash movement)
    // Cash Flow = Net Income + Depreciation - Principal Payment + (Any one-time cash inflows like Sales Rev were in EBITDA)
    // Actually, simple way: Cash In - Cash Out
    // Cash In = YearRevenue
    // Cash Out = YearOpEx + InterestPayment + PrincipalPayment + Tax

    const netCashFlow = yearRevenue - yearOpEx - interestPayment - principalPayment - tax;

    cashFlow.push(netCashFlow);
  }

  // --- TOTALS ---
  const totalCarbonRevenue = params.enableCarbonCredits 
    ? (totalRecoveredVolume * co2TonnesPerVolumeUnit) * params.pricePerCredit
    : 0;

  const totalRevenue = salesRevenue + totalLeasingRevenue + installationRevenue + totalCarbonRevenue + totalMonthlyFeeRevenue;

  const totalMaintenance = annualMaintenance * durationYears;
  const totalWarranty = annualWarranty * durationYears;
  const totalConsumables = annualConsumables * durationYears;
  const totalOperational = annualOperational * durationYears;
  const totalElectricity = isLeasing ? (totalAnnualElectricity * durationYears) : 0;

  const totalOpEx = totalMaintenance + totalWarranty + totalConsumables + totalOperational + totalElectricity;
  const totalCosts = cogs + installationCost + customerAcquisitionCost + totalOpEx + totalLoanInterestCost;

  const netProfit = totalRevenue - totalCosts - totalTaxes; // Post-tax lifetime profit

  // NPV
  let npv = 0;
  cashFlow.forEach((flow, i) => {
      npv += flow / Math.pow(1 + params.discountRate / 100, i);
  });

  return {
    totalUnitsSold,
    revenue: {
      salesRevenue,
      leasingRevenue: totalLeasingRevenue,
      installationRevenue,
      carbonCreditRevenue: totalCarbonRevenue,
      monthlyFeeRevenue: totalMonthlyFeeRevenue,
      totalRevenue,
    },
    costs: {
      cogs,
      installationCost,
      maintenanceCost: totalMaintenance,
      electricityCost: totalElectricity,
      consumablesCost: totalConsumables,
      warrantyCost: totalWarranty,
      operationalCost: totalOperational,
      customerAcquisitionCost,
      loanInterestCost: totalLoanInterestCost,
      totalCosts,
      totalTaxes,
    },
    profitability: {
      grossProfit: totalRevenue - cogs - installationCost, // Simplified Gross
      ebitda: totalRevenue - totalOpEx - cogs - installationCost - customerAcquisitionCost,
      netProfit,
      profitMargin: totalRevenue > 0 ? (netProfit / totalRevenue) * 100 : 0,
      roi: (totalCosts + totalTaxes) > 0 ? (netProfit / (totalCosts + totalTaxes)) * 100 : 0,
      npv,
    },
    cashFlow
  };
};

import React, { useState } from 'react';
import { InputParams } from '../types';
import ToggleSwitch from './ToggleSwitch';
import SliderInput from './SliderInput';
import TextInput from './TextInput';
import SegmentedControl from './SegmentedControl';
import SelectInput from './SelectInput';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';
import { ChevronDownIcon, ChevronUpIcon } from './icons';
import { PRESETS } from '../utils/presets';

interface InputPanelProps {
  params: InputParams;
  onParamChange: (key: keyof InputParams, value: string | number | boolean) => void;
  currency: string;
  onCurrencyChange: (currency: string) => void;
}

// Accordion Item Component
const AccordionItem: React.FC<{
  title: string;
  isOpen: boolean;
  onToggle: () => void;
  children: React.ReactNode;
  badge?: string;
}> = ({ title, isOpen, onToggle, children, badge }) => {
  return (
    <div className={`border border-glass-border rounded-xl overflow-hidden mb-3 transition-all duration-300 ${isOpen ? 'bg-glass-200 shadow-lg' : 'bg-glass-100 hover:bg-glass-200'}`}>
      <button
        onClick={onToggle}
        className="w-full flex items-center justify-between p-4 text-left focus:outline-none"
      >
        <div className="flex items-center space-x-3">
             <span className={`font-bold text-sm ${isOpen ? 'text-white' : 'text-navy-200'}`}>{title}</span>
             {badge && <span className="text-[10px] uppercase font-bold bg-white/10 text-primary-light px-2 py-0.5 rounded-full border border-white/10 tracking-wide shadow-sm">{badge}</span>}
        </div>
        {isOpen ? <ChevronUpIcon className="w-4 h-4 text-primary-light" /> : <ChevronDownIcon className="w-4 h-4 text-navy-400" />}
      </button>
      <div className={`transition-all duration-300 ease-in-out overflow-hidden ${isOpen ? 'max-h-[800px] opacity-100' : 'max-h-0 opacity-0'}`}>
        <div className="p-4 pt-0 space-y-5 border-t border-glass-border bg-black/10">
            <div className="h-2"></div> {/* Spacer */}
            {children}
        </div>
      </div>
    </div>
  );
};

const InputPanel: React.FC<InputPanelProps> = ({ params, onParamChange, currency, onCurrencyChange }) => {
  const [openSections, setOpenSections] = useState<Record<string, boolean>>({
    'client': true,
    'operations': false,
    'financials': true,
    'carbon': false,
    'advanced': false,
    'finance': false,
  });

  const toggleSection = (section: string) => {
    setOpenSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const applyPreset = (presetName: string) => {
      const preset = PRESETS.find(p => p.name === presetName);
      if (preset) {
          // Bulk update
          Object.entries(preset.params).forEach(([key, value]) => {
              onParamChange(key as keyof InputParams, value);
          });
      }
  };

  return (
    <div id="input-panel-container" className="h-full flex flex-col">
        {/* Header Config */}
        <div className="mb-4 space-y-4 p-1">
            <div>
                 <label className="block text-[10px] font-bold text-navy-400 uppercase tracking-widest mb-2">Smart Preset</label>
                 <select 
                    onChange={(e) => applyPreset(e.target.value)}
                    className="w-full bg-navy-900 border border-white/20 rounded-lg py-2 px-3 text-sm text-white focus:ring-primary focus:border-primary"
                    defaultValue=""
                 >
                     <option value="" disabled>Select a configuration...</option>
                     {PRESETS.map(p => <option key={p.name} value={p.name}>{p.name}</option>)}
                 </select>
            </div>
            <div>
                <label className="block text-[10px] font-bold text-navy-400 uppercase tracking-widest mb-2">Business Model</label>
                <SegmentedControl
                    options={['Direct Sales', 'Leasing']}
                    selected={params.businessModel}
                    setSelected={(val) => onParamChange('businessModel', val)}
                />
            </div>
             <SelectInput 
                label="Currency"
                value={currency}
                onChange={onCurrencyChange}
                options={[
                    { value: 'USD', label: '$ USD' },
                    { value: 'EUR', label: '€ EUR' },
                    { value: 'GBP', label: '£ GBP' },
                    { value: 'JPY', label: '¥ JPY' },
                    { value: 'CAD', label: '$ CAD' },
                ]}
            />
        </div>

        <div className="flex-1 overflow-y-auto pr-2 -mr-2 custom-scrollbar space-y-1 pb-10">
             <label className="block text-[10px] font-bold text-navy-400 uppercase tracking-widest mb-2 pl-1">Input Parameters</label>

            <AccordionItem 
                title="Site & Client Info" 
                isOpen={openSections['client']} 
                onToggle={() => toggleSection('client')}
            >
                <SliderInput
                    label="Units per Client"
                    value={params.unitsPerClient}
                    min={1} max={200} step={1}
                    onChange={(v) => onParamChange('unitsPerClient', v)}
                />
                <TextInput
                    label="Number of Clients"
                    value={params.numberOfClients}
                    onChange={(v) => onParamChange('numberOfClients', v)}
                />
                <ToggleSwitch
                    label="Company Installs?"
                    enabled={params.companyHandlesInstallation}
                    onChange={(v) => onParamChange('companyHandlesInstallation', v)}
                />
            </AccordionItem>

            <AccordionItem 
                title="Operational Metrics" 
                isOpen={openSections['operations']} 
                onToggle={() => toggleSection('operations')}
            >
                <TextInput
                    label={`Avg. Gasoline Sold (${params.unitSystem === 'gallons' ? 'Gal' : 'L'}/Day)`}
                    value={params.avgGasolineSold}
                    onChange={(v) => onParamChange('avgGasolineSold', v)}
                />
                <SliderInput
                    label="Volume Growth Rate"
                    value={params.volumeGrowthRate}
                    min={-5} max={20} step={0.5}
                    unit="%"
                    onChange={(v) => onParamChange('volumeGrowthRate', v)}
                />
                <SliderInput
                    label="Recovery Rate"
                    value={params.recoveryRate}
                    min={0.05} max={1} step={0.05}
                    unit="%"
                    onChange={(v) => onParamChange('recoveryRate', v)}
                />
                <SliderInput
                    label="Machine Uptime"
                    value={params.machineUptime}
                    min={90} max={100} step={0.1}
                    unit="%"
                    onChange={(v) => onParamChange('machineUptime', v)}
                />
            </AccordionItem>

            <AccordionItem 
                title="Financial Parameters" 
                isOpen={openSections['financials']} 
                onToggle={() => toggleSection('financials')}
            >
                 {params.businessModel === 'Leasing' ? (
                    <>
                        <TextInput
                            label={`Gasoline Price (${CURRENCY_SYMBOLS[currency]}/${params.unitSystem === 'gallons' ? 'Gal' : 'L'})`}
                            value={params.gasolinePrice}
                            onChange={(v) => onParamChange('gasolinePrice', v)}
                        />
                        <SliderInput
                            label="Revenue Share"
                            value={params.companyRevenueShare}
                            min={1} max={100} step={1}
                            unit="%"
                            onChange={(v) => onParamChange('companyRevenueShare', v)}
                        />
                    </>
                 ) : (
                    <TextInput
                        label="Unit Sale Price"
                        value={params.unitSalePrice}
                        onChange={(v) => onParamChange('unitSalePrice', v)}
                        unit={CURRENCY_SYMBOLS[currency]}
                    />
                 )}
                 <TextInput
                    label="Contract/Lease Term (Years)"
                    value={params.leaseTerm}
                    onChange={(v) => onParamChange('leaseTerm', v)}
                />
                 {/* SaaS Option */}
                <div className="pt-4 border-t border-white/10 mt-4">
                    <ToggleSwitch
                        label="Enable Monthly SaaS Fee"
                        enabled={params.enableMonthlyFees}
                        onChange={(v) => onParamChange('enableMonthlyFees', v)}
                    />
                    {params.enableMonthlyFees && (
                        <div className="mt-3">
                            <TextInput
                                label="Monthly Fee Per Unit"
                                value={params.monthlyFeePerUnit}
                                onChange={(v) => onParamChange('monthlyFeePerUnit', v)}
                                unit={CURRENCY_SYMBOLS[currency]}
                            />
                        </div>
                    )}
                </div>
            </AccordionItem>

            <AccordionItem 
                title="Project Finance & Tax" 
                isOpen={openSections['finance']} 
                onToggle={() => toggleSection('finance')}
                badge="Advanced"
            >
                <ToggleSwitch
                    label="Enable Debt Financing"
                    enabled={params.enableFinancing}
                    onChange={(v) => onParamChange('enableFinancing', v)}
                />
                {params.enableFinancing && (
                    <div className="space-y-4 mt-3 pl-2 border-l-2 border-primary/30">
                        <SliderInput
                            label="Down Payment"
                            value={params.loanDownPaymentPercent}
                            min={0} max={100} step={5}
                            unit="%"
                            onChange={(v) => onParamChange('loanDownPaymentPercent', v)}
                        />
                         <SliderInput
                            label="Interest Rate (APR)"
                            value={params.loanInterestRate}
                            min={0} max={20} step={0.5}
                            unit="%"
                            onChange={(v) => onParamChange('loanInterestRate', v)}
                        />
                        <TextInput
                            label="Loan Term (Years)"
                            value={params.loanTermYears}
                            onChange={(v) => onParamChange('loanTermYears', v)}
                        />
                    </div>
                )}

                <div className="pt-4 border-t border-white/10 mt-4">
                     <SliderInput
                        label="Corporate Tax Rate"
                        value={params.corporateTaxRate}
                        min={0} max={50} step={1}
                        unit="%"
                        onChange={(v) => onParamChange('corporateTaxRate', v)}
                    />
                     <TextInput
                        label="Depreciation Period (Years)"
                        value={params.depreciationPeriod}
                        onChange={(v) => onParamChange('depreciationPeriod', v)}
                    />
                </div>
            </AccordionItem>

            <AccordionItem 
                title="Carbon Credits" 
                isOpen={openSections['carbon']} 
                onToggle={() => toggleSection('carbon')}
            >
                <ToggleSwitch
                    label="Enable Carbon Credits"
                    enabled={params.enableCarbonCredits}
                    onChange={(v) => onParamChange('enableCarbonCredits', v)}
                />
                {params.enableCarbonCredits && (
                    <SliderInput
                        label="Price per Credit"
                        value={params.pricePerCredit}
                        min={5} max={100} step={1}
                        unit={CURRENCY_SYMBOLS[currency]}
                        onChange={(v) => onParamChange('pricePerCredit', v)}
                    />
                )}
            </AccordionItem>

            <AccordionItem 
                title="Analysis Settings" 
                isOpen={openSections['advanced']} 
                onToggle={() => toggleSection('advanced')}
            >
                <ToggleSwitch
                    label="Discount Cash Flow"
                    enabled={params.enableCashFlowDiscounting}
                    onChange={(v) => onParamChange('enableCashFlowDiscounting', v)}
                />
                {params.enableCashFlowDiscounting && (
                    <SliderInput
                        label="Discount Rate"
                        value={params.discountRate}
                        min={1} max={25} step={0.5}
                        unit="%"
                        onChange={(v) => onParamChange('discountRate', v)}
                    />
                )}
            </AccordionItem>
        </div>
    </div>
  );
};

export default InputPanel;

import React from 'react';
import { CalculatorIcon, ChartBarIcon, BeakerIcon, FolderIcon, ClipboardListIcon, TableIcon, ViewBoardsIcon } from './icons';

interface SidebarProps {
  activePage: 'model' | 'assumptions' | 'sensitivity' | 'scenarios' | 'lease-analysis' | 'monte-carlo' | 'comparison';
  onNavigate: (page: any) => void;
}

