import React, { useState, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, ReferenceLine, Cell } from 'recharts';
import { InputParams, CalculatedResults } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';
import Card from './Card';
import SliderInput from './SliderInput';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';

interface MonteCarloAnalysisProps {
  baseParams: InputParams;
  currency: string;
}

const formatCurrency = (val: number, currency: string) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact' }).format(val);

const MonteCarloAnalysis: React.FC<MonteCarloAnalysisProps> = ({ baseParams, currency }) => {
  const [uncertainty, setUncertainty] = useState(15); // +/- %
  const [simulationCount, setSimulationCount] = useState(500);
  const [isSimulating, setIsSimulating] = useState(false);
  const [results, setResults] = useState<number[]>([]);

  const runSimulation = () => {
      setIsSimulating(true);
      // Use setTimeout to allow UI to render loading state
      setTimeout(() => {
          const newResults: number[] = [];

          for(let i=0; i<simulationCount; i++) {
              // Perturb key inputs
              // Using Box-Muller transform for simple normal distribution approximation could be better, 
              // but uniform random within range is clearer for "Uncertainty Range" user mental model.
              // Let's use Uniform for simplicity: Base * (1 + (Math.random() - 0.5) * 2 * uncertainty/100)

              const vary = (val: number) => val * (1 + (Math.random() - 0.5) * 2 * (uncertainty / 100));

              const simParams = { ...baseParams };

              // Variables to perturb
              simParams.avgGasolineSold = vary(baseParams.avgGasolineSold);
              simParams.gasolinePrice = vary(baseParams.gasolinePrice);
              simParams.recoveryRate = Math.min(100, Math.max(0, vary(baseParams.recoveryRate))); // Clamp 0-100

              const res = calculateVaporRecovery(simParams);
              newResults.push(res.profitability.netProfit);
          }

          setResults(newResults.sort((a,b) => a - b));
          setIsSimulating(false);
      }, 100);
  };

  const histogramData = useMemo(() => {
      if (results.length === 0) return [];

      const min = results[0];
      const max = results[results.length - 1];
      const binCount = 20;
      const binSize = (max - min) / binCount;

      const bins = Array.from({ length: binCount }, (_, i) => ({
          rangeStart: min + i * binSize,
          rangeEnd: min + (i + 1) * binSize,
          name: formatCurrency(min + i * binSize + binSize/2, currency), // Label center
          count: 0
      }));

      results.forEach(val => {
          const binIndex = Math.min(binCount - 1, Math.floor((val - min) / binSize));
          bins[binIndex].count++;
      });

      return bins;
  }, [results, currency]);

  const stats = useMemo(() => {
      if (results.length === 0) return null;
      const sum = results.reduce((a, b) => a + b, 0);
      const avg = sum / results.length;
      const positiveCount = results.filter(r => r > 0).length;
      const probSuccess = (positiveCount / results.length) * 100;

      return {
          avg,
          min: results[0],
          max: results[results.length - 1],
          probSuccess
      };
  }, [results]);

  return (
    <div className="p-6 lg:p-8 w-full max-w-6xl mx-auto h-full overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
            <div>
                <h1 className="text-3xl font-bold text-white">Monte Carlo Simulation</h1>
                <p className="text-navy-400 mt-1">Probabilistic risk assessment based on input uncertainty.</p>
            </div>
            <button
                onClick={runSimulation}
                disabled={isSimulating}
                className="bg-primary hover:bg-primary-dark text-navy-950 font-bold px-6 py-3 rounded-xl transition-all shadow-lg hover:shadow-primary/30 disabled:opacity-50"
            >
                {isSimulating ? 'Running...' : 'Run Simulation'}
            </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-1 space-y-6">
                <Card title="Configuration">
                    <SliderInput 
                        label="Uncertainty Range (+/- %)"
                        value={uncertainty}
                        min={5} max={50} step={5}
                        unit="%"
                        onChange={setUncertainty}
                        description="Variability applied to Volume, Price, and Recovery Rate."
                    />
                     <div className="mt-4">
                        <label className="text-xs text-navy-400 font-bold uppercase">Iterations</label>
                        <select 
                            value={simulationCount}
                            onChange={(e) => setSimulationCount(parseInt(e.target.value))}
                            className="w-full bg-navy-900 border border-white/20 rounded mt-2 px-3 py-2 text-white"
                        >
                            <option value="100">100 Runs (Fast)</option>
                            <option value="500">500 Runs (Balanced)</option>
                            <option value="1000">1000 Runs (Precise)</option>
                        </select>
                     </div>
                </Card>

                {stats && (
                    <Card title="Results Summary" className="bg-gradient-to-br from-navy-900 to-navy-950">
                        <div className="space-y-4">
                            <div>
                                <div className="text-navy-400 text-xs uppercase tracking-wider">Probability of Profit</div>
                                <div className={`text-4xl font-black ${stats.probSuccess > 80 ? 'text-success' : stats.probSuccess > 50 ? 'text-warning' : 'text-danger'}`}>
                                    {stats.probSuccess.toFixed(1)}%
                                </div>
                            </div>
                             <div>
                                <div className="text-navy-400 text-xs uppercase tracking-wider">Average Net Outcome</div>
                                <div className="text-xl font-bold text-white">
                                    {formatCurrency(stats.avg, currency)}
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4 pt-2 border-t border-white/10">
                                <div>
                                    <div className="text-navy-500 text-[10px] uppercase">Worst Case</div>
                                    <div className="text-danger font-mono font-bold">{formatCurrency(stats.min, currency)}</div>
                                </div>
                                <div>
                                    <div className="text-navy-500 text-[10px] uppercase">Best Case</div>
                                    <div className="text-success font-mono font-bold">{formatCurrency(stats.max, currency)}</div>
                                </div>
                            </div>
                        </div>
                    </Card>
                )}
            </div>

            <div className="lg:col-span-2 h-[500px] bg-card border border-white/10 rounded-2xl p-4">
                {results.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={histogramData} margin={{ top: 20, right: 30, left: 20, bottom: 20 }}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.1)" />
                            <XAxis 
                                dataKey="name" 
                                stroke="#94a3b8" 
                                tick={{fontSize: 10}}
                                interval={2}
                            />
                            <YAxis stroke="#94a3b8" />
                            <Tooltip 
                                cursor={{fill: 'rgba(255,255,255,0.05)'}}
                                contentStyle={{backgroundColor: '#0f172a', borderColor: '#334155', color: '#fff'}}
                            />
                            <ReferenceLine x={0} stroke="white" />
                            <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                                {histogramData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.rangeStart < 0 ? '#ef4444' : '#10b981'} />
                                ))}
                            </Bar>
                        </BarChart>
                    </ResponsiveContainer>
                ) : (
                    <div className="h-full flex flex-col items-center justify-center text-navy-500">
                        <p>No simulation data.</p>
                        <button onClick={runSimulation} className="text-primary hover:underline mt-2">Run Simulation</button>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

export default MonteCarloAnalysis;

import React, { useState, useEffect } from 'react';
import { InputParams, Scenario, CalculatedResults } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';
import { PRESETS } from '../utils/presets';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';
import Card from './Card';

interface ScenarioComparisonProps {
  currentParams: InputParams;
  currency: string;
}

const formatCurrency = (val: number, currency: string) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact', compactDisplay: 'short' }).format(val);

const formatPercent = (val: number) => `${val.toFixed(1)}%`;

const ScenarioComparison: React.FC<ScenarioComparisonProps> = ({ currentParams, currency }) => {
  const [savedScenarios, setSavedScenarios] = useState<Scenario[]>([]);
  const [selectedScenarioId, setSelectedScenarioId] = useState<string>('preset-standard');

  // Combine Presets and User Scenarios for the dropdown
  const allOptions = [
      ...PRESETS.map((p, idx) => ({ id: `preset-${idx}`, name: `[Preset] ${p.name}`, params: { ...currentParams, ...p.params } })),
      ...savedScenarios
  ];

  useEffect(() => {
      const saved = localStorage.getItem('masarzero_scenarios');
      if (saved) {
          try { setSavedScenarios(JSON.parse(saved)); } catch(e) {}
      }
  }, []);

  const scenarioB = allOptions.find(s => s.id === selectedScenarioId) || allOptions[0];
  const paramsA = currentParams;
  const paramsB = scenarioB.params;

  const resultsA = calculateVaporRecovery(paramsA);
  const resultsB = calculateVaporRecovery(paramsB);

  const getDelta = (valA: number, valB: number, type: 'currency' | 'percent' = 'currency') => {
      const diff = valA - valB; // Current - Baseline
      const format = type === 'currency' ? (v: number) => formatCurrency(v, currency) : formatPercent;
      const color = diff > 0 ? 'text-success' : diff < 0 ? 'text-danger' : 'text-navy-400';
      const sign = diff > 0 ? '+' : '';
      return <span className={`text-xs font-bold ${color}`}>{sign}{format(diff)}</span>;
  };

  const MetricRow = ({ label, valA, valB, type = 'currency' }: { label: string, valA: number, valB: number, type?: 'currency'|'percent' }) => (
      <div className="grid grid-cols-3 gap-4 py-4 border-b border-white/5 hover:bg-white/5 transition-colors px-4">
          <div className="text-navy-200 font-medium flex flex-col justify-center">
             {label}
          </div>
          <div className="bg-primary/5 rounded p-2 text-right">
              <div className="font-bold text-white text-lg">{type === 'currency' ? formatCurrency(valA, currency) : formatPercent(valA)}</div>
              <div className="text-[10px] text-navy-400 uppercase tracking-wider mt-1">Current</div>
          </div>
          <div className="bg-navy-900 rounded p-2 text-right relative overflow-hidden">
               <div className="font-bold text-navy-100 text-lg">{type === 'currency' ? formatCurrency(valB, currency) : formatPercent(valB)}</div>
               <div className="flex justify-between items-center mt-1">
                  <span className="text-[10px] text-navy-500 uppercase tracking-wider">Baseline</span>
                  {getDelta(valA, valB, type)}
               </div>
          </div>
      </div>
  );

  return (
    <div className="p-6 lg:p-8 w-full max-w-5xl mx-auto h-full overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
            <h1 className="text-3xl font-bold text-white">Scenario Comparison</h1>
            <div className="w-64">
                <label className="block text-[10px] font-bold text-navy-400 uppercase tracking-widest mb-2">Compare Against</label>
                <select 
                    className="w-full bg-navy-900 border border-white/20 rounded-lg px-3 py-2 text-sm text-white"
                    value={selectedScenarioId}
                    onChange={(e) => setSelectedScenarioId(e.target.value)}
                >
                    {allOptions.map(opt => (
                        <option key={opt.id} value={opt.id}>{opt.name}</option>
                    ))}
                </select>
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            <div className="bg-gradient-primary p-4 rounded-xl shadow-lg border border-white/10">
                <div className="text-white/60 text-xs font-bold uppercase tracking-widest mb-1">Current Active Scenario</div>
                <div className="text-2xl font-black text-white">Scenario A</div>
            </div>
            <div className="bg-navy-800 p-4 rounded-xl shadow-lg border border-white/10">
                <div className="text-navy-400 text-xs font-bold uppercase tracking-widest mb-1">Baseline Comparison</div>
                <div className="text-2xl font-black text-navy-100 truncate">{scenarioB.name}</div>
            </div>
        </div>

        <Card title="Financial Performance" noPadding>
            <MetricRow label="Net Profit (Lifetime)" valA={resultsA.profitability.netProfit} valB={resultsB.profitability.netProfit} />
            <MetricRow label="Net Present Value (NPV)" valA={resultsA.profitability.npv} valB={resultsB.profitability.npv} />
            <MetricRow label="Return on Investment (ROI)" valA={resultsA.profitability.roi} valB={resultsB.profitability.roi} type="percent" />
            <MetricRow label="Total Revenue" valA={resultsA.revenue.totalRevenue} valB={resultsB.revenue.totalRevenue} />
            <MetricRow label="Total Costs" valA={resultsA.costs.totalCosts} valB={resultsB.costs.totalCosts} />
            <MetricRow label="Total Taxes" valA={resultsA.costs.totalTaxes} valB={resultsB.costs.totalTaxes} />
        </Card>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-6">
            <Card title="Operational Differences">
                 <div className="space-y-3 text-sm">
                     <div className="flex justify-between"><span className="text-navy-400">Model</span> <span className="text-white">{paramsA.businessModel} vs {paramsB.businessModel}</span></div>
                     <div className="flex justify-between"><span className="text-navy-400">Total Units</span> <span className="text-white">{(paramsA.unitsPerClient * paramsA.numberOfClients)} vs {(paramsB.unitsPerClient * paramsB.numberOfClients)}</span></div>
                     <div className="flex justify-between"><span className="text-navy-400">Term</span> <span className="text-white">{paramsA.leaseTerm}y vs {paramsB.leaseTerm}y</span></div>
                 </div>
            </Card>
             <Card title="Key Assumptions">
                 <div className="space-y-3 text-sm">
                     <div className="flex justify-between"><span className="text-navy-400">Gas Price</span> <span className="text-white">{formatCurrency(paramsA.gasolinePrice, currency)} vs {formatCurrency(paramsB.gasolinePrice, currency)}</span></div>
                     <div className="flex justify-between"><span className="text-navy-400">Recovery Rate</span> <span className="text-white">{paramsA.recoveryRate}% vs {paramsB.recoveryRate}%</span></div>
                     <div className="flex justify-between"><span className="text-navy-400">SaaS Enabled</span> <span className="text-white">{paramsA.enableMonthlyFees ? 'Yes' : 'No'} vs {paramsB.enableMonthlyFees ? 'Yes' : 'No'}</span></div>
                 </div>
            </Card>
        </div>

    </div>
  );
};

