import { createPortal } from 'react-dom';

interface Step {
  target: string;
  title: string;
  content: string;
  preferredPosition: 'top' | 'bottom' | 'left' | 'right';
}

interface OnboardingTourProps {
  isOpen: boolean;
  onClose: () => void;
}

const steps: Step[] = [
  {
    target: 'body',
    title: 'Welcome to MasarZero v3.0',
