import React, { useState, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, ReferenceLine, Cell, CartesianGrid } from 'recharts';
import { InputParams, CalculatedResults } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';
import Card from './Card';
import SliderInput from './SliderInput';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';

interface MonteCarloAnalysisProps {
  baseParams: InputParams;
  currency: string;
}

const formatCurrency = (val: number, currency: string) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact' }).format(val);

const MonteCarloAnalysis: React.FC<MonteCarloAnalysisProps> = ({ baseParams, currency }) => {
  const [uncertainty, setUncertainty] = useState(15); // +/- %
  const [simulationCount, setSimulationCount] = useState(500);
  const [isSimulating, setIsSimulating] = useState(false);
  const [results, setResults] = useState<number[]>([]);

  const runSimulation = () => {
      setIsSimulating(true);
      // Use setTimeout to allow UI to render loading state
      setTimeout(() => {
          const newResults: number[] = [];

          for(let i=0; i<simulationCount; i++) {
              // Perturb key inputs
              // Using Box-Muller transform for simple normal distribution approximation could be better, 
              // but uniform random within range is clearer for "Uncertainty Range" user mental model.
              // Let's use Uniform for simplicity: Base * (1 + (Math.random() - 0.5) * 2 * uncertainty/100)

              const vary = (val: number) => val * (1 + (Math.random() - 0.5) * 2 * (uncertainty / 100));

              const simParams = { ...baseParams };

              // Variables to perturb
              simParams.avgGasolineSold = vary(baseParams.avgGasolineSold);
              simParams.gasolinePrice = vary(baseParams.gasolinePrice);
              simParams.recoveryRate = Math.min(100, Math.max(0, vary(baseParams.recoveryRate))); // Clamp 0-100

              const res = calculateVaporRecovery(simParams);
              newResults.push(res.profitability.netProfit);
          }

          setResults(newResults.sort((a,b) => a - b));
          setIsSimulating(false);
      }, 100);
  };

  const histogramData = useMemo(() => {
      if (results.length === 0) return [];

      const min = results[0];
      const max = results[results.length - 1];
      const binCount = 20;
      const binSize = (max - min) / binCount;

      const bins = Array.from({ length: binCount }, (_, i) => ({
          rangeStart: min + i * binSize,
          rangeEnd: min + (i + 1) * binSize,
          name: formatCurrency(min + i * binSize + binSize/2, currency), // Label center
          count: 0
      }));

      results.forEach(val => {
          const binIndex = Math.min(binCount - 1, Math.floor((val - min) / binSize));
          bins[binIndex].count++;
      });

      return bins;
  }, [results, currency]);

  const stats = useMemo(() => {
      if (results.length === 0) return null;
      const sum = results.reduce((a, b) => a + b, 0);
      const avg = sum / results.length;
      const positiveCount = results.filter(r => r > 0).length;
      const probSuccess = (positiveCount / results.length) * 100;

      return {
          avg,
          min: results[0],
          max: results[results.length - 1],
          probSuccess
      };
  }, [results]);

  return (
    <div className="p-6 lg:p-8 w-full max-w-6xl mx-auto h-full overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
            <div>
                <h1 className="text-3xl font-bold text-white">Monte Carlo Simulation</h1>
                <p className="text-navy-400 mt-1">Probabilistic risk assessment based on input uncertainty.</p>
            </div>
            <button
                onClick={runSimulation}
                disabled={isSimulating}
                className="bg-primary hover:bg-primary-dark text-navy-950 font-bold px-6 py-3 rounded-xl transition-all shadow-lg hover:shadow-primary/30 disabled:opacity-50"
            >
                {isSimulating ? 'Running...' : 'Run Simulation'}
            </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
            <div className="lg:col-span-1 space-y-6">
                <Card title="Configuration">
                    <SliderInput 
                        label="Uncertainty Range (+/- %)"
                        value={uncertainty}
                        min={5} max={50} step={5}
                        unit="%"
                        onChange={setUncertainty}
                        description="Variability applied to Volume, Price, and Recovery Rate."
                    />
                     <div className="mt-4">
                        <label className="text-xs text-navy-400 font-bold uppercase">Iterations</label>
                        <select 
                            value={simulationCount}
                            onChange={(e) => setSimulationCount(parseInt(e.target.value))}
                            className="w-full bg-navy-900 border border-white/20 rounded mt-2 px-3 py-2 text-white"
                        >
                            <option value="100">100 Runs (Fast)</option>
                            <option value="500">500 Runs (Balanced)</option>
                            <option value="1000">1000 Runs (Precise)</option>
                        </select>
                     </div>
                </Card>

                {stats && (
                    <Card title="Results Summary" className="bg-gradient-to-br from-navy-900 to-navy-950">
                        <div className="space-y-4">
                            <div>
                                <div className="text-navy-400 text-xs uppercase tracking-wider">Probability of Profit</div>
                                <div className={`text-4xl font-black ${stats.probSuccess > 80 ? 'text-success' : stats.probSuccess > 50 ? 'text-warning' : 'text-danger'}`}>
                                    {stats.probSuccess.toFixed(1)}%
                                </div>
                            </div>
                             <div>
                                <div className="text-navy-400 text-xs uppercase tracking-wider">Average Net Outcome</div>
                                <div className="text-xl font-bold text-white">
                                    {formatCurrency(stats.avg, currency)}
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4 pt-2 border-t border-white/10">
                                <div>
                                    <div className="text-navy-500 text-[10px] uppercase">Worst Case</div>
                                    <div className="text-danger font-mono font-bold">{formatCurrency(stats.min, currency)}</div>
                                </div>
                                <div>
                                    <div className="text-navy-500 text-[10px] uppercase">Best Case</div>
                                    <div className="text-success font-mono font-bold">{formatCurrency(stats.max, currency)}</div>
                                </div>
                            </div>
                        </div>
                    </Card>
                )}
            </div>

            <div className="lg:col-span-2 h-[500px] bg-card border border-white/10 rounded-2xl p-4">
                {results.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={histogramData} margin={{ top: 20, right: 30, left: 20, bottom: 20 }}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.1)" />
                            <XAxis 
                                dataKey="name" 
                                stroke="#94a3b8" 
                                tick={{fontSize: 10}}
                                interval={2}
                            />
                            <YAxis stroke="#94a3b8" />
                            <Tooltip 
                                cursor={{fill: 'rgba(255,255,255,0.05)'}}
                                contentStyle={{backgroundColor: '#0f172a', borderColor: '#334155', color: '#fff'}}
                            />
                            <ReferenceLine x={0} stroke="white" />
                            <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                                {histogramData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.rangeStart < 0 ? '#ef4444' : '#10b981'} />
                                ))}
                            </Bar>
                        </BarChart>
                    </ResponsiveContainer>
                ) : (
                    <div className="h-full flex flex-col items-center justify-center text-navy-500">
                        <p>No simulation data.</p>
                        <button onClick={runSimulation} className="text-primary hover:underline mt-2">Run Simulation</button>
                    </div>
                )}
            </div>
        </div>

        {/* Methodology Explanation */}
        <div className="bg-navy-900/50 p-6 rounded-xl border border-white/5">
            <h3 className="text-lg font-bold text-white mb-2">Methodology</h3>
            <p className="text-sm text-navy-300 leading-relaxed">
                This Monte Carlo simulation performs {simulationCount} random iterations to estimate the probability distribution of your project's Net Profit.
                For each iteration, the calculator randomly varies three key inputs—<strong>Gasoline Volume</strong>, <strong>Gasoline Price</strong>, and <strong>Recovery Rate</strong>—within the specified "Uncertainty Range" (Uniform Distribution).
                <br/><br/>
                For example, a 15% uncertainty on a $1.00 gas price means the simulator will randomly pick a price between $0.85 and $1.15 for each run. This helps identify the likelihood of breaking even or achieving high returns under volatile market conditions.
            </p>
        </div>
    </div>
  );
};

export default MonteCarloAnalysis;

