import React, { useState, useMemo, useEffect } from 'react';
import { InputParams, AnalyzableVariable, AnalyzableMetric } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';
import { SENSITIVITY_CONFIG, METRIC_CONFIG, CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';
import SensitivityChart from './SensitivityChart';
import SensitivityHeatmap from './SensitivityHeatmap';
import Card from './Card';
import Dropdown from './Dropdown';
import SliderInput from './SliderInput';
import ToggleSwitch from './ToggleSwitch';
import { AdjustmentsIcon, ChartBarIcon, TableIcon } from './icons';

interface SensitivityAnalysisProps {
  baseParams: InputParams;
  onBaseParamChange: (key: keyof InputParams, value: string | number | boolean) => void;
  currency: string;
}

type AnalysisMode = '1D' | '2D';

const SensitivityAnalysis: React.FC<SensitivityAnalysisProps> = ({ baseParams, onBaseParamChange, currency }) => {
  const [isControlsOpen, setIsControlsOpen] = useState(true);
  const [analysisMode, setAnalysisMode] = useState<AnalysisMode>('1D');

  const availableVariables = useMemo(() => {
    return (Object.keys(SENSITIVITY_CONFIG) as AnalyzableVariable[])
      .filter(key => SENSITIVITY_CONFIG[key].models.includes(baseParams.businessModel));
  }, [baseParams.businessModel]);

  const availableMetrics = useMemo(() => {
    const allMetrics = Object.keys(METRIC_CONFIG) as AnalyzableMetric[];
    if (baseParams.businessModel === 'Direct Sales') {
      return allMetrics.filter(m => m !== 'npv');
    }
    return allMetrics;
  }, [baseParams.businessModel]);

  const [analyzedVariableX, setAnalyzedVariableX] = useState<AnalyzableVariable>(availableVariables[0]);
  const [analyzedVariableY, setAnalyzedVariableY] = useState<AnalyzableVariable>(availableVariables[1] || availableVariables[0]);
  const [analyzedMetric, setAnalyzedMetric] = useState<AnalyzableMetric>(availableMetrics[0]);

  useEffect(() => {
    if (!availableVariables.includes(analyzedVariableX)) {
      setAnalyzedVariableX(availableVariables[0]);
    }
    if (!availableVariables.includes(analyzedVariableY)) {
      setAnalyzedVariableY(availableVariables[1] || availableVariables[0]);
    }
    if (!availableMetrics.includes(analyzedMetric)) {
        setAnalyzedMetric(availableMetrics[0]);
    }
  }, [availableVariables, availableMetrics, analyzedVariableX, analyzedVariableY, analyzedMetric]);

  const chartData = useMemo(() => {
    if (analysisMode === '1D') {
      if (!analyzedVariableX) return [];
      const config = SENSITIVITY_CONFIG[analyzedVariableX];
      const data = [];
      const iterations = Math.min(100, Math.floor((config.max - config.min) / config.step) + 1);
      const step = (config.max - config.min) / (iterations - 1);

      for (let i = 0; i < iterations; i++) {
        const value = config.min + i * step;
        const modifiedParams: InputParams = { ...baseParams, [analyzedVariableX]: value };
        const results = calculateVaporRecovery(modifiedParams);
        const yValue = analyzedMetric === 'totalRevenue' ? results.revenue.totalRevenue : results.profitability[analyzedMetric];
        data.push({ xValue: value, yValue });
      }
      return data;
    } else { // 2D Mode
      if (!analyzedVariableX || !analyzedVariableY) return [];
      const xConfig = SENSITIVITY_CONFIG[analyzedVariableX];
      const yConfig = SENSITIVITY_CONFIG[analyzedVariableY];
      const data = [];
      const steps = 20; // Fixed steps for performance
      const xStep = (xConfig.max - xConfig.min) / (steps - 1);
      const yStep = (yConfig.max - yConfig.min) / (steps - 1);

      for (let i = 0; i < steps; i++) {
        const xValue = xConfig.min + i * xStep;
        for (let j = 0; j < steps; j++) {
          const yValue = yConfig.min + j * yStep;
          const modifiedParams: InputParams = { ...baseParams, [analyzedVariableX]: xValue, [analyzedVariableY]: yValue };
          const results = calculateVaporRecovery(modifiedParams);
          const zValue = analyzedMetric === 'totalRevenue' ? results.revenue.totalRevenue : results.profitability[analyzedMetric];
          data.push({ x: xValue, y: yValue, z: zValue, xLabel: xConfig.label, yLabel: yConfig.label, xUnit: xConfig.unit, yUnit: yConfig.unit });
        }
      }
      return data;
    }
  }, [analysisMode, analyzedVariableX, analyzedVariableY, analyzedMetric, baseParams]);

  const isGasAnalysisActive = useMemo(() => {
    const activeVars = [analyzedVariableX];
    if (analysisMode === '2D') {
      activeVars.push(analyzedVariableY);
    }
    return activeVars.includes('gasolinePrice') || activeVars.includes('recoveryRate');
  }, [analysisMode, analyzedVariableX, analyzedVariableY]);

  const { annualGasolineRecovered, unitSystemLabel } = useMemo(() => {
      if (baseParams.businessModel !== 'Leasing') return { annualGasolineRecovered: 0, unitSystemLabel: '' };
      const totalUnitsSold = baseParams.unitsPerClient * baseParams.numberOfClients;
      const recovered = baseParams.avgGasolineSold * totalUnitsSold * (baseParams.recoveryRate / 100) * 365 * (baseParams.machineUptime / 100);
      const label = baseParams.unitSystem === 'gallons' ? 'Gallons' : 'Liters';
      return {
          annualGasolineRecovered: recovered,
          unitSystemLabel: label,
      };
  }, [baseParams]);

  const xConfig = SENSITIVITY_CONFIG[analyzedVariableX];
  const yConfig = SENSITIVITY_CONFIG[analyzedVariableY];
  const metricConfig = METRIC_CONFIG[analyzedMetric];

  return (
    <div className="w-full h-full flex flex-col p-6 lg:p-8">
      <div className="flex-shrink-0 flex items-center justify-between mb-2">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
             {analysisMode === '1D' && <ChartBarIcon className="w-8 h-8 text-primary" />}
             {analysisMode === '2D' && <TableIcon className="w-8 h-8 text-primary" />}
             Sensitivity Analysis
          </h1>
          <p className="text-md text-navy-400 mt-1">
            Visualize how key variables affect profitability.
          </p>
        </div>
         <div className="flex items-center space-x-2">
           <button 
             className="flex items-center space-x-2 px-4 py-2 bg-primary text-navy-950 rounded-lg text-sm font-bold hover:bg-primary-light transition-colors"
             onClick={() => setIsControlsOpen(!isControlsOpen)}
           >
            <AdjustmentsIcon className="w-5 h-5"/>
            <span>Controls</span>
           </button>
        </div>
      </div>

      {isControlsOpen && (
         <div className="flex-shrink-0 my-6 bg-card border border-white/10 p-6 rounded-xl">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <div className="lg:col-span-2">
                    <label className="block text-sm font-medium text-navy-200 mb-2">Analysis Mode</label>
                    <div className="flex items-center p-1 space-x-1 bg-navy-900 rounded-lg">
                        {(['1D', '2D'] as AnalysisMode[]).map(mode => (
                            <button 
                                key={mode}
                                onClick={() => setAnalysisMode(mode)}
                                className={`w-full py-2 text-sm font-medium leading-5 rounded-md transition-colors duration-200 flex items-center justify-center gap-2
                                ${analysisMode === mode 
                                    ? 'bg-navy-950 shadow text-white border border-white/10' 
                                    : 'text-navy-400 hover:bg-white/5 hover:text-white'
                                }`}
                            >
                                {mode === '1D' && <ChartBarIcon className="w-4 h-4"/>}
                                {mode === '2D' && <TableIcon className="w-4 h-4" />}
                                <span>{mode}</span>
                            </button>
                        ))}
                    </div>
                </div>
                <div>
                    <Dropdown
                        label="Metric to Analyze"
                        options={availableMetrics.map(key => ({ value: key, label: METRIC_CONFIG[key].label }))}
                        value={analyzedMetric}
                        onChange={(val) => setAnalyzedMetric(val)}
                    />
                </div>
                <div>
                     <Dropdown
                        label="Business Model"
                        options={[ {value: 'Leasing', label: 'Leasing'}, {value: 'Direct Sales', label: 'Direct Sales'} ]}
                        value={baseParams.businessModel}
                        onChange={(val) => onBaseParamChange('businessModel', val)}
                    />
                </div>

                <>
                    <div>
                        <Dropdown
                            label={analysisMode === '1D' ? "Variable to Analyze" : "X-Axis Variable"}
                            options={availableVariables.map(key => ({ value: key, label: SENSITIVITY_CONFIG[key].label }))}
                            value={analyzedVariableX}
                            onChange={(val) => setAnalyzedVariableX(val)}
                        />
                    </div>
                    {analysisMode === '2D' && (
                        <div>
                            <Dropdown
                                label="Y-Axis Variable"
                                options={availableVariables.filter(v => v !== analyzedVariableX).map(key => ({ value: key, label: SENSITIVITY_CONFIG[key].label }))}
                                value={analyzedVariableY}
                                onChange={(val) => setAnalyzedVariableY(val)}
                            />
                        </div>
                    )}
                </>
            </div>
         </div>
      )}

      {/* Main Chart Area */}
      <div className="flex-1 min-h-[500px] mb-8 relative">
        {analysisMode === '1D' && (
          <SensitivityChart 
            data={chartData}
            xKey="xValue"
            yKey="yValue"
            xLabel={`${xConfig?.label || ''} ${xConfig?.unit ? `(${xConfig.unit})` : ''}`}
            yLabel={metricConfig?.label || ''}
            currency={currency}
          />
        )}
        {analysisMode === '2D' && (
          <SensitivityHeatmap 
            data={chartData}
            xConfig={xConfig}
            yConfig={yConfig}
            metric={analyzedMetric}
            currency={currency}
          />
        )}
      </div>

       <div className="flex-shrink-0 mt-8 mb-8">
        <h3 className="text-xl font-bold text-white mb-4">Quick Parameters</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {isGasAnalysisActive && baseParams.businessModel === 'Leasing' ? (
              <Card title="Key Revenue Drivers" description="Adjust other variables in the revenue formula.">
                  <SliderInput
                      label="Units per Client"
                      value={baseParams.unitsPerClient}
                      min={1} max={200} step={1}
                      onChange={(v) => onBaseParamChange('unitsPerClient', v)}
                  />
                  <SliderInput
                      label="Company Revenue Share"
                      value={baseParams.companyRevenueShare}
                      min={10} max={90} step={5}
                      unit="%"
                      onChange={(v) => onBaseParamChange('companyRevenueShare', v)}
                  />
              </Card>
          ) : (
              <Card title="Base Scenario Snapshot" description="Key operational assumptions for this analysis.">
                  <div className="space-y-4">
                      <div className="flex justify-between items-center text-sm">
                          <span className="text-navy-300">Gasoline Price</span>
                          <span className="font-bold text-white">{new Intl.NumberFormat('en-US', { style: 'currency', currency: currency, minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(baseParams.gasolinePrice)} / {unitSystemLabel}</span>
                      </div>
                      <div className="flex justify-between items-center text-sm">
                          <span className="text-navy-300">Annual Gasoline Recovered</span>
                          <span className="font-bold text-white">{annualGasolineRecovered.toLocaleString(undefined, {maximumFractionDigits: 0})} {unitSystemLabel}</span>
                      </div>
                  </div>
              </Card>
          )}

          <Card title="Operational Toggles" description="Adjust installation and carbon credit settings.">
              <ToggleSwitch
                  label="Company Handles Installation"
                  enabled={baseParams.companyHandlesInstallation}
                  onChange={(v) => onBaseParamChange('companyHandlesInstallation', v)}
              />
              {baseParams.businessModel === 'Leasing' && (
                  <>
                      <ToggleSwitch
                          label="Enable Carbon Credits"
                          enabled={baseParams.enableCarbonCredits}
                          onChange={(v) => onBaseParamChange('enableCarbonCredits', v)}
                      />
                      {baseParams.enableCarbonCredits && (
                          <SliderInput
                              label="Carbon Credit Price"
                              value={baseParams.pricePerCredit}
                              min={5} max={100} step={1}
                              unit={CURRENCY_SYMBOLS[currency]}
                              onChange={(v) => onBaseParamChange('pricePerCredit', v)}
                          />
                      )}
                  </>
              )}
          </Card>
        </div>
       </div>

    </div>
  );
};

export default SensitivityAnalysis;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, Cell } from 'recharts';
import { InputParams, Scenario } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';

interface FootballFieldChartProps {
  scenarios: { name: string; params: InputParams; isCurrent?: boolean }[];
  currency: string;
}

const CustomTooltip = ({ active, payload, currency }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0]?.payload; // The colored bar payload
    if (!data) return null;

    const fmt = (val: number) => 
        new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact' }).format(val);

    return (
      <div className="bg-navy-900 border border-white/20 rounded-lg p-4 shadow-lg text-sm w-64 z-50">
        <p className="font-bold text-white text-base mb-2 border-b border-white/10 pb-2">{data.name}</p>

        <div className="space-y-2">
            <div className="flex justify-between">
                <span className="text-danger font-bold text-xs">Pessimistic</span>
                <span className="text-white font-mono">{fmt(data.low)}</span>
            </div>
            <div className="flex justify-between">
                 <span className="text-navy-300 font-bold text-xs">Base Case</span>
                 <span className="text-white font-mono border-b border-primary/50">{fmt(data.base)}</span>
            </div>
            <div className="flex justify-between">
                <span className="text-success font-bold text-xs">Optimistic</span>
                <span className="text-white font-mono">{fmt(data.high)}</span>
            </div>
        </div>
      </div>
    );
  }
  return null;
};

const FootballFieldChart: React.FC<FootballFieldChartProps> = ({ scenarios, currency }) => {
  const chartData = useMemo(() => {
    return scenarios.map(scenario => {
        // Base Calculation
        const baseRes = calculateVaporRecovery(scenario.params);
        const baseVal = baseRes.profitability.netProfit;

        // Pessimistic (-15% on drivers: Price, Recovery, Volume)
        const pessParams = { 
            ...scenario.params,
            gasolinePrice: scenario.params.gasolinePrice * 0.85,
            avgGasolineSold: scenario.params.avgGasolineSold * 0.85,
            recoveryRate: Math.max(0, scenario.params.recoveryRate * 0.85)
        };
        const pessRes = calculateVaporRecovery(pessParams);
        const lowVal = pessRes.profitability.netProfit;

        // Optimistic (+15% on drivers)
        const optParams = { 
            ...scenario.params,
            gasolinePrice: scenario.params.gasolinePrice * 1.15,
            avgGasolineSold: scenario.params.avgGasolineSold * 1.15,
            recoveryRate: Math.min(1, scenario.params.recoveryRate * 1.15)
        };
        const optRes = calculateVaporRecovery(optParams);
        const highVal = optRes.profitability.netProfit;

        const spread = highVal - lowVal;

        return {
            name: scenario.name,
            low: lowVal,
            base: baseVal,
            high: highVal,
            start: lowVal, // Start of the bar (transparent)
            spread: spread, // Visible width
            isCurrent: scenario.isCurrent
        };
    }).sort((a, b) => b.base - a.base); // Sort by Base Value

  }, [scenarios]);

  const allValues = chartData.flatMap(d => [d.low, d.high]);
  const minDomain = Math.min(...allValues) * (Math.min(...allValues) < 0 ? 1.1 : 0.9);
  const maxDomain = Math.max(...allValues) * 1.1;

  const formatTick = (val: number) => new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact' }).format(val);

  return (
    <div className="h-full w-full min-h-[400px]">
        <div className="mb-2 text-center">
            <p className="text-xs text-navy-400 italic">
               Range based on ±15% sensitivity on Price, Volume, and Recovery.
            </p>
        </div>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart
          layout="vertical"
          data={chartData}
          margin={{ top: 20, right: 30, left: 120, bottom: 20 }}
          barSize={20}
        >
          <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="rgba(255, 255, 255, 0.1)" />
          <XAxis 
            type="number" 
            domain={[minDomain, maxDomain]} 
            tickFormatter={formatTick}
            stroke="#94a3b8"
            tick={{ fontSize: 10 }}
          />
          <YAxis 
            type="category" 
            dataKey="name" 
            stroke="#94a3b8" 
            width={140}
            tick={({ x, y, payload }) => {
                 const isCurrent = chartData.find(c => c.name === payload.value)?.isCurrent;
                 return (
                     <g transform={`translate(${x},${y})`}>
                         <text x={-10} y={4} textAnchor="end" fill={isCurrent ? '#3B82F6' : '#94a3b8'} fontSize={11} fontWeight={isCurrent ? 700 : 400}>
                             {payload.value}
                         </text>
                     </g>
                 )
            }}
          />
          <Tooltip 
            cursor={{ fill: 'rgba(255,255,255,0.05)' }} 
            content={<CustomTooltip currency={currency} />} 
          />

          {/* Invisible Bar to offset start */}
          <Bar dataKey="start" stackId="a" fill="transparent" isAnimationActive={false} />

          {/* Visible Range Bar */}
          <Bar dataKey="spread" stackId="a" radius={[4, 4, 4, 4]}>
            {chartData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill="url(#scenarioGradient)" stroke={entry.isCurrent ? '#3B82F6' : 'none'} strokeWidth={1} />
            ))}
          </Bar>

          {/* Reference Line for "Zero" */}
          <ReferenceLine x={0} stroke="#475569" />

          <defs>
            <linearGradient id="scenarioGradient" x1="0" y1="0" x2="1" y2="0">
              <stop offset="0%" stopColor="#EF4444" stopOpacity={0.7} />
              <stop offset="50%" stopColor="#3B82F6" stopOpacity={0.7} />
              <stop offset="100%" stopColor="#10B981" stopOpacity={0.7} />
            </linearGradient>
          </defs>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default FootballFieldChart;

import React, { useState, useEffect } from 'react';
import { InputParams, Scenario, CalculatedResults } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';
import { PRESETS } from '../utils/presets';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';
import Card from './Card';
import FootballFieldChart from './FootballFieldChart';

interface ScenarioComparisonProps {
  currentParams: InputParams;
  currency: string;
}

const formatCurrency = (val: number, currency: string) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact', compactDisplay: 'short' }).format(val);

const formatPercent = (val: number) => `${val.toFixed(1)}%`;

const ScenarioComparison: React.FC<ScenarioComparisonProps> = ({ currentParams, currency }) => {
  const [savedScenarios, setSavedScenarios] = useState<Scenario[]>([]);
  const [selectedScenarioId, setSelectedScenarioId] = useState<string>('preset-standard');

  // Combine Presets and User Scenarios for the dropdown
  const allOptions = [
      ...PRESETS.map((p, idx) => ({ id: `preset-${idx}`, name: `[Preset] ${p.name}`, params: { ...currentParams, ...p.params } })),
      ...savedScenarios
  ];

  useEffect(() => {
      const saved = localStorage.getItem('masarzero_scenarios');
      if (saved) {
          try { setSavedScenarios(JSON.parse(saved)); } catch(e) {}
      }
  }, []);

  const scenarioB = allOptions.find(s => s.id === selectedScenarioId) || allOptions[0];
  const paramsA = currentParams;
  const paramsB = scenarioB.params;

  const resultsA = calculateVaporRecovery(paramsA);
  const resultsB = calculateVaporRecovery(paramsB);

  // Prepare data for the football field comparison
  // We include Current, Selected Comparison, and top 2 presets to fill the chart
  const footballFieldScenarios = [
      { name: 'Current Configuration', params: currentParams, isCurrent: true },
      { name: scenarioB.name, params: paramsB },
      ...PRESETS.slice(0, 3).filter(p => `[Preset] ${p.name}` !== scenarioB.name).map(p => ({
          name: p.name,
          params: { ...currentParams, ...p.params }
      }))
  ];

  const getDelta = (valA: number, valB: number, type: 'currency' | 'percent' = 'currency') => {
      const diff = valA - valB; // Current - Baseline
      const format = type === 'currency' ? (v: number) => formatCurrency(v, currency) : formatPercent;
      const color = diff > 0 ? 'text-success' : diff < 0 ? 'text-danger' : 'text-navy-400';
      const sign = diff > 0 ? '+' : '';
      return <span className={`text-xs font-bold ${color}`}>{sign}{format(diff)}</span>;
  };

  const MetricRow = ({ label, valA, valB, type = 'currency' }: { label: string, valA: number, valB: number, type?: 'currency'|'percent' }) => (
      <div className="grid grid-cols-3 gap-4 py-4 border-b border-white/5 hover:bg-white/5 transition-colors px-4">
          <div className="text-navy-200 font-medium flex flex-col justify-center">
             {label}
          </div>
          <div className="bg-primary/5 rounded p-2 text-right">
              <div className="font-bold text-white text-lg">{type === 'currency' ? formatCurrency(valA, currency) : formatPercent(valA)}</div>
              <div className="text-[10px] text-navy-400 uppercase tracking-wider mt-1">Current</div>
          </div>
          <div className="bg-navy-900 rounded p-2 text-right relative overflow-hidden">
               <div className="font-bold text-navy-100 text-lg">{type === 'currency' ? formatCurrency(valB, currency) : formatPercent(valB)}</div>
               <div className="flex justify-between items-center mt-1">
                  <span className="text-[10px] text-navy-500 uppercase tracking-wider">Baseline</span>
                  {getDelta(valA, valB, type)}
               </div>
          </div>
      </div>
  );

  return (
    <div className="w-full h-full p-6 lg:p-8 overflow-y-auto">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
            <div>
                <h1 className="text-3xl font-bold text-white">Scenario Comparison</h1>
                <p className="text-navy-400 mt-1">Evaluate your current model against saved scenarios and presets.</p>
            </div>
            <div className="w-full md:w-64">
                <label className="block text-[10px] font-bold text-navy-400 uppercase tracking-widest mb-2">Compare Against</label>
                <select 
                    className="w-full bg-navy-900 border border-white/20 rounded-lg px-3 py-2 text-sm text-white"
                    value={selectedScenarioId}
                    onChange={(e) => setSelectedScenarioId(e.target.value)}
                >
                    {allOptions.map(opt => (
                        <option key={opt.id} value={opt.id}>{opt.name}</option>
                    ))}
                </select>
            </div>
        </div>

        {/* Comparison Football Field */}
        <div className="mb-8">
            <Card title="Net Profit Comparison (Scenario Range)" description="Comparing the Net Profit range (Pessimistic vs Optimistic) across different scenarios.">
                 <div className="h-[400px] w-full">
                     <FootballFieldChart scenarios={footballFieldScenarios} currency={currency} />
                 </div>
            </Card>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            <div className="bg-gradient-primary p-4 rounded-xl shadow-lg border border-white/10">
                <div className="text-white/60 text-xs font-bold uppercase tracking-widest mb-1">Current Active Scenario</div>
                <div className="text-2xl font-black text-white">Scenario A</div>
            </div>
            <div className="bg-navy-800 p-4 rounded-xl shadow-lg border border-white/10">
                <div className="text-navy-400 text-xs font-bold uppercase tracking-widest mb-1">Baseline Comparison</div>
                <div className="text-2xl font-black text-navy-100 truncate">{scenarioB.name}</div>
            </div>
        </div>

        <Card title="Financial Performance" noPadding>
            <MetricRow label="Net Profit (Lifetime)" valA={resultsA.profitability.netProfit} valB={resultsB.profitability.netProfit} />
            <MetricRow label="Net Present Value (NPV)" valA={resultsA.profitability.npv} valB={resultsB.profitability.npv} />
            <MetricRow label="Return on Investment (ROI)" valA={resultsA.profitability.roi} valB={resultsB.profitability.roi} type="percent" />
            <MetricRow label="Total Revenue" valA={resultsA.revenue.totalRevenue} valB={resultsB.revenue.totalRevenue} />
            <MetricRow label="Total Costs" valA={resultsA.costs.totalCosts} valB={resultsB.costs.totalCosts} />
            <MetricRow label="Total Taxes" valA={resultsA.costs.totalTaxes} valB={resultsB.costs.totalTaxes} />
        </Card>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-6 pb-12">
            <Card title="Operational Differences">
                 <div className="space-y-3 text-sm">
                     <div className="flex justify-between"><span className="text-navy-400">Model</span> <span className="text-white">{paramsA.businessModel} vs {paramsB.businessModel}</span></div>
                     <div className="flex justify-between"><span className="text-navy-400">Total Units</span> <span className="text-white">{(paramsA.unitsPerClient * paramsA.numberOfClients)} vs {(paramsB.unitsPerClient * paramsB.numberOfClients)}</span></div>
                     <div className="flex justify-between"><span className="text-navy-400">Term</span> <span className="text-white">{paramsA.leaseTerm}y vs {paramsB.leaseTerm}y</span></div>
                 </div>
            </Card>
             <Card title="Key Assumptions">
                 <div className="space-y-3 text-sm">
                     <div className="flex justify-between"><span className="text-navy-400">Gas Price</span> <span className="text-white">{formatCurrency(paramsA.gasolinePrice, currency)} vs {formatCurrency(paramsB.gasolinePrice, currency)}</span></div>
                     <div className="flex justify-between"><span className="text-navy-400">Recovery Rate</span> <span className="text-white">{paramsA.recoveryRate}% vs {paramsB.recoveryRate}%</span></div>
                     <div className="flex justify-between"><span className="text-navy-400">SaaS Enabled</span> <span className="text-white">{paramsA.enableMonthlyFees ? 'Yes' : 'No'} vs {paramsB.enableMonthlyFees ? 'Yes' : 'No'}</span></div>
                 </div>
            </Card>
        </div>

    </div>
  );
};

export default ScenarioComparison;
